import boto3
import json

sqs = boto3.client('sqs', region_name='us-west-2')
QUEUE_URL = 'your_queue_url_here'

def send_message(data):
    message = {
        'Body': json.dumps(data),
    }
    response = sqs.send_message(QueueUrl=QUEUE_URL, MessageBody=json.dumps(message))

